-- Table structure for table `packages`
--

DROP TABLE IF EXISTS `packages`;
CREATE TABLE `packages` (
  `id` int NOT NULL,
  `title` varchar(200) COLLATE utf8mb4_general_ci NOT NULL,
  `destination` varchar(200) COLLATE utf8mb4_general_ci NOT NULL,
  `category` enum('domestic','international') COLLATE utf8mb4_general_ci NOT NULL,
  `duration` varchar(50) COLLATE utf8mb4_general_ci NOT NULL,
  `description` text COLLATE utf8mb4_general_ci,
  `image_url` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `pdf_url` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `flag` varchar(50) COLLATE utf8mb4_general_ci DEFAULT 'location',
  `price_amount` decimal(10,2) DEFAULT NULL,
  `price_currency` varchar(10) COLLATE utf8mb4_general_ci DEFAULT 'INR',
  `display_price` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT '1',
  `display_order` int DEFAULT '0',
  `featured` tinyint(1) DEFAULT '0',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- --------------------------------------------------------

--
-- Table structure for table `passports`
--

DROP TABLE IF EXISTS `passports`;
CREATE TABLE `passports` (
  `id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `passport_number` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `email` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `passportCategory` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `type` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `country` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `issueDate` datetime DEFAULT NULL,
  `expiryDate` datetime DEFAULT NULL,
  `name` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `status` varchar(255) COLLATE utf8mb4_general_ci DEFAULT 'Active',
  `renewProcess` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin,
  `referenceBy` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  `leadId` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `userId` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `date` datetime DEFAULT NULL,
  `leadStatus` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `phoneNumber` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `remark` text COLLATE utf8mb4_general_ci,
  `assignedTo` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `processDate` datetime DEFAULT NULL,
  `processStatus` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `processRemark` text COLLATE utf8mb4_general_ci,
  `portalId` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `portalPassword` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `portalLink` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL
) ;

