DROP TABLE IF EXISTS `quotations`;
CREATE TABLE `quotations` (
  `id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `enquiryNo` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `status` varchar(255) COLLATE utf8mb4_general_ci DEFAULT 'draft',
  `inclusions` text COLLATE utf8mb4_general_ci,
  `exclusions` text COLLATE utf8mb4_general_ci,
  `itinerary` text COLLATE utf8mb4_general_ci,
  `visaExclusions` text COLLATE utf8mb4_general_ci,
  `flightDetails` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin,
  `mealPlan` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  `leadId` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `userId` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `quotationNo` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `internalRemark` text COLLATE utf8mb4_general_ci,
  `accommodationDetails` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin
) ;

