('0c522ef9-ddfa-465d-91e2-231f227eae2c', '12092025016', 'draft', '<ul><li><strong>Panoramic City Drive</strong></li><li><strong>Ice cream Museum</strong></li><li><strong>MBS Sky park{Dated-Non peak hrs}+Garden by the bay{Flower dome+Cloud Forest-Jurassic world}</strong></li><li><strong>Universal Studios</strong></li><li><strong>Sentosa tour with (Island Admission+1 Way Cable Car+Sea Aquarium+Luge&amp;skyride</strong></li><li><strong>(3 round)+wings of time</strong></li><li><strong>Return Airport transfers</strong></li><li><strong>All tours and transfers on pvt</strong></li></ul>', '<p><br></p>', '<ul><li><strong>Panoramic City Drive</strong></li><li><strong>Ice cream Museum</strong></li><li><strong>MBS Sky park{Dated-Non peak hrs}+Garden by the bay{Flower dome+Cloud Forest-Jurassic world}</strong></li><li><strong>Universal Studios</strong></li><li><strong>Sentosa tour with (Island Admission+1 Way Cable Car+Sea Aquarium+Luge&amp;skyride(3 round)+wings of time</strong></li><li><strong>Return Airport transfers</strong></li></ul>', '<p><br></p>', '{}', 'Continental Plan (CP)', '2025-09-13 13:08:31', '2025-09-15 08:45:44', '1471303b-ef66-4c9b-bb15-09ad277fe22c', '74e78145-addf-4775-9806-7d9116108aa5', '12092025016_Q02', NULL, '{\"1757672909079\":{\"adults\":\"1133\",\"extraAdults\":\"1113\",\"childWithBed\":\"1067\",\"childWithoutBed\":\"\",\"childsBelow5\":\"\",\"remarks\":\"PROVIDED RATES ARE BASED ON SGD.\\n\\n\",\"rows\":[{\"key\":\"1757672911711\",\"hotelName\":\"NOVOTEL SINGAPORE KITCHENER\",\"destination\":\"SINGAPORE\",\"checkIn\":\"2025-10-18\",\"checkOut\":\"2025-09-24\",\"roomCategory\":\"STANDARD ROOM\",\"noOfRooms\":\"3\"}]}}'),
('0fa26e10-4afd-4ff1-9ce9-df8fcba2ea66', NULL, 'draft', NULL, NULL, NULL, NULL, NULL, NULL, '2025-08-25 05:45:43', '2025-08-25 05:45:43', NULL, '0d88fbdc-1552-4281-a5de-206a35a3f42d', '25082025001_Q01', NULL, NULL),
('138f6b0d-d364-4428-824d-7a522e10d010', '14102025024', 'draft', '<p>Hotel Accommodation</p><p>Air Tickets</p><p>Visa</p><p>All Sightseeing on Private Basis</p><p>All Transfers on Private Basis&nbsp;</p>', '<ul><li>Tourism Dirham if not mentioned in the inclusions&nbsp;</li><li>Visa &amp; Insurance if not mentioned in the inclusions&nbsp;</li><li>OTB is not included in the package. (It depends upon the airline)&nbsp;</li><li>Any expense of personal nature not mentioned in the inclusions&nbsp;</li><li>Tips / Gratuities&nbsp;</li><li>Any meals/excursions not mentioned in the inclusions&nbsp;</li></ul>', '<p><strong>DAY 1</strong></p><ul><li><strong>Airport Transfer</strong>&nbsp;from DUBAI INTERNATIONAL AIRPORT T1/T2/T3</li><li><strong>Marina Dhow Cruise Dinner - Standard&nbsp;</strong>:&nbsp;<span style=\"color: rgb(13, 13, 13);\">A relaxing cruise with the view of sky scrapers of Dubai Marina with lavish buffet dinner and entertainment show on board</span></li></ul><p><strong>DAY 2</strong></p><ul><li><strong>Dubai Half Day City Tour - 5 Hour (Private)</strong>&nbsp;: Experience panoramic half day city tour of Dubai and enjoy Old and New Dubai sightseeing.</li><li><strong>Monorail Ticket&nbsp;</strong>:&nbsp;<span style=\"color: rgb(13, 13, 13);\">The most iconic way to navigate across the Palm Jumeirah. It is not a mere form of transportation; it\'s an experiential journey.</span></li><li><strong>Standard Dubai Desert Safari 4X4 with Camel Ride, BBQ Dinner, Belly Dance show (Private)</strong>&nbsp;: Enjoy Magical &amp; Memorable Evening with Dune Bashing, BBQ Dinner and Entertainment Shows</li></ul><p><strong>DAY 3</strong></p><ul><li><strong>Dubai Frame&nbsp;</strong>:&nbsp;<strong>:&nbsp;</strong>An architectural landmark which holds the record for the largest frame in the world</li><li><strong>Museum of the Future&nbsp;</strong>: The Museum of the Future is an exhibition space for innovative and futuristic ideologies, services, and products&nbsp;<strong style=\"color: rgb(192, 57, 43);\"><em>(Subject to availability at time of booking)</em></strong></li><li><strong>At The Top Burj Khalifa - 124th floor Non-Prime&nbsp;</strong>:Enjoy breathtaking panoramic views of Dubai from the 124th floor of the world’s tallest tower during non-prime hours -&nbsp;<strong>Non Prime Hours :&nbsp;07:30am – 11:30 am &amp;&nbsp;08:30pm – 11:00pm&nbsp;</strong></li></ul><p><strong>DAY 4</strong></p><ul><li><strong>10 Seater Chrysler 300 Pearl/Emerald Edition (Black/ White Colour)</strong>&nbsp;(1 Hours - Hour Based)</li><li><strong>The View at the Palm Non-prime&nbsp;</strong>: Enjoy incomparable views of one of Dubai’s most talked about landmarks at The View at The Palm.</li><li><strong>Miracle Garden&nbsp;</strong>:&nbsp;<span style=\"color: rgb(13, 13, 13);\">World\'s largest natural flower garden, featuring over 50 million flowers and 250 million plants.&nbsp;</span></li><li><strong>Global Village&nbsp;</strong>:&nbsp;<span style=\"color: rgb(13, 13, 13);\">World\'s largest tourism, leisure, shopping and entertainment project by combining cultures of 90 countries</span></li></ul><p><strong>DAY 5</strong></p><ul><li><strong>Day at Leisure</strong></li></ul><p><strong>DAY 6</strong></p><ul><li><strong>Day at Leisure</strong></li></ul><p><strong>DAY 7</strong></p><ul><li><strong>Full Day Abu Dhabi City Tour - 10 Hour (Private)</strong>&nbsp;: Discover the rich heritage and modern marvels of the UAE’s capital with our immersive Abu Dhabi City Tour.&nbsp;&nbsp;</li><li><strong>Grand Mosque Entry Ticket&nbsp;</strong>: Entry for Grand mosque Abu Dhabi</li><li><strong>BAPS Hindu Mandir, Abu Dhabi&nbsp;</strong>: Entry to BAPS Temple Abu Dhabi&nbsp;</li></ul><p><strong>DAY 8</strong></p><ul><li><strong>Day at Leisure</strong></li></ul><p><strong>DAY 9</strong></p><ul><li><strong>Airport Transfer</strong>&nbsp;to DUBAI INTERNATIONAL AIRPORT T1/T2/T3</li><li>All the above rates are inclusive of 5 % VAT</li><li>All Tours and Transfers are based on&nbsp;<strong>PVT basis</strong></li></ul>', '<p>Tourist Visa Charges Rs. 7800 Per Person</p><p><br></p><p><strong><u>Documents Required For Tourist Visa </u></strong></p><p>Passport Cover Page Front and Last Banne Jose</p><p>Passport First and Last Page</p><p>Photo</p><p>Pancard</p><p>Aadhar Card</p><p>Hotel</p><p>Air Ticket</p>', '{\"1760620030168\":{\"ratePerPerson\":\"35190\",\"remarks\":\"Tickets Are Non Refundable in Case of Cancelation.\",\"rows\":[{\"key\":\"1760620035065\",\"travelDate\":\"2025-12-10\",\"flightNo\":\"SG 15\",\"departure\":\"Ahmedabad\",\"arrival\":\"Dubai\",\"departureTime\":\"16:25\",\"arrivalTime\":\"18:25\",\"passenger\":\"5\",\"baggage\":\"30\"},{\"key\":\"1760620145500\",\"travelDate\":\"2025-12-18\",\"flightNo\":\"SG 16\",\"departure\":\"Dubai\",\"arrival\":\"Ahmedabad\",\"departureTime\":\"19:25\",\"arrivalTime\":\"23:35\",\"passenger\":\"5\",\"baggage\":\"30\"}]}}', 'Continental Plan (CP)', '2025-10-16 10:06:16', '2025-10-16 13:44:33', '3c98b511-ba3b-48fa-b663-4cb381924222', '0d88fbdc-1552-4281-a5de-206a35a3f42d', '14102025024_Q02', NULL, '{\"1760620570673\":{\"adults\":\"1074\",\"extraAdults\":\"732\",\"childWithBed\":\"\",\"childWithoutBed\":\"\",\"childsBelow5\":\"\",\"remarks\":\"Hotel Rates in USD\",\"rows\":[{\"key\":\"1760620580098\",\"hotelName\":\"Savoy Crest Hotel Apartments\",\"destination\":\"Dubai\",\"checkIn\":\"2025-12-10\",\"checkOut\":\"2025-12-16\",\"roomCategory\":\"STUDIO ROOM\",\"noOfRooms\":\"2\"},{\"key\":\"1760620656772\",\"hotelName\":\"Crowne Plaza Abu Dhabi - Yas Island\",\"destination\":\"Abu Dhabi\",\"checkIn\":\"2025-12-16\",\"checkOut\":\"2025-12-18\",\"roomCategory\":\"STANDARD ROOM\",\"noOfRooms\":\"2\"}]}}'),
