('5b8afbf4-aa66-4930-89f3-0b5ba6edb9eb', '28082025006', 'draft', '<ul><li><strong style=\"color: rgb(0, 0, 0);\">Airport Transfer</strong></li><li><strong style=\"color: rgb(0, 0, 0);\">Marina Dhow Cruise Dinner - Standard&nbsp;</strong></li><li><strong style=\"color: rgb(0, 0, 0);\">Dubai Half Day City Tour -&nbsp;(Private)</strong></li><li><strong style=\"color: rgb(0, 0, 0);\">At the top Burj Khalifa - 124th floor Non-Prime</strong></li><li><strong style=\"color: rgb(0, 0, 0);\">The View at the Palm Non-prime&nbsp;</strong></li><li><strong style=\"color: rgb(0, 0, 0);\">Dubai Frame</strong></li><li><strong style=\"color: rgb(0, 0, 0);\">Standard Dubai Desert Safari 4X4 with Camel Ride, BBQ Dinner, Belly Dance show (Private)</strong></li><li><strong style=\"color: rgb(0, 0, 0);\">Atlantis Aqua Venture water park + Lost chamber</strong></li><li><strong>Day at Leisure</strong></li><li><strong style=\"color: rgb(0, 0, 0);\">Full Day Abu Dhabi City Tour - (Private)</strong></li><li><strong>BAPS Temple&nbsp;</strong>&nbsp;</li><li><strong>Ferrari Yas Island Theme Park</strong></li><li><strong><em><u>All Tours on PVT Basis.</u></em></strong></li></ul>', '<ul><li><strong>Tourism Dirham if not mentioned in the inclusions</strong></li><li><strong>Visa &amp; Insurance if not mentioned in the inclusions</strong></li><li><strong>OTB is not included in the package. (It depends upon the airline)</strong></li><li><strong>Any expense of personal nature not mentioned in the inclusions</strong></li><li><strong>Tips / Gratuities</strong></li><li><strong>Any meals/excursions not mentioned in the inclusions</strong></li><li><strong>Any Specific tax/Special Tax is not mention in the inclusions</strong></li></ul>', '<p><strong>DAY 1</strong></p><ul><li><strong>Airport Transfer</strong>&nbsp;from DUBAI INTERNATIONAL AIRPORT T1/T2/T3</li><li><strong>Marina Dhow Cruise Dinner - Standard&nbsp;</strong>:&nbsp;A relaxing cruise with the view of sky scrapers of Dubai Marina with lavish buffet dinner and entertainment show on board</li></ul><p><strong>DAY 2</strong></p><ul><li><strong>Dubai Half Day City Tour -&nbsp;(Private)</strong>&nbsp;: Experience panoramic half day city tour of Dubai and enjoy Old and New Dubai sightseeing.</li><li><strong>At the top Burj Khalifa - 124th floor Non-Prime&nbsp;</strong>: The tallest structure and building in the world:&nbsp;&nbsp;And enjoy shopping at Dubai Mall; But not to miss the fascinating Fountain Show</li></ul><p><strong>DAY 3</strong></p><ul><li><strong>The View at the Palm Non-prime&nbsp;</strong>: Enjoy incomparable views of one of Dubai’s most talked about landmarks at The View at The Palm.</li><li><strong>Dubai Frame&nbsp;</strong>:&nbsp;<strong>:&nbsp;</strong>An architectural landmark which holds the record for the largest frame in the world</li></ul><p><strong>DAY 4</strong></p><ul><li><strong>Standard Dubai Desert Safari 4X4 with Camel Ride, BBQ Dinner, Belly Dance show (Private)</strong>&nbsp;: Enjoy Magical &amp; Memorable Evening with Dune Bashing, BBQ Dinner and Entertainment Shows</li></ul><p><strong>DAY 5</strong></p><ul><li><strong>Atlantis Aqua Venture water park + Lost chamber&nbsp;</strong>: World\'s largest waterpark promises a world of excitement to make you feel different in Water in more ways than one . Atlantis-themed aquarium with underwater halls &amp; tunnels housing marine life, plus feeding sessions.</li></ul><p><strong>DAY 6</strong></p><ul><li><strong>Day at Leisure</strong></li></ul><p><strong>DAY 7</strong></p><ul><li><strong>Full Day Abu Dhabi City Tour - (Private)</strong>&nbsp;: Discover the rich heritage and modern marvels of the UAE’s capital with our immersive Abu Dhabi City Tour.&nbsp;</li><li><strong>BAPS Temple&nbsp;</strong>&nbsp;</li><li><strong>Ferrari Yas Island Theme Park&nbsp;</strong>:</li><li>Ferrari World Abu Dhabi is a mostly indoors theme park located on Yas Island in Abu Dhabi, United Arab Emirates.</li></ul><p><strong>DAY 8</strong></p><ul><li><strong>Airport Transfer</strong>&nbsp;to DUBAI INTERNATIONAL AIRPORT T1/T2/T3</li></ul>', '<p>Visa Charges Rs. 7500</p>', '[{\"key\":1756388090926,\"journeyDate\":\"2025-09-10\",\"flightNo\":\"E6 1477\",\"arrival\":\"Dubai (4:15 A.M )\",\"departure\":\"Ahmedabad (2:55 A.M)\",\"passenger\":\"6\",\"baggage\":\"30 kg\",\"fees\":\"\"},{\"key\":1756388091152,\"journeyDate\":\"2025-09-17\",\"flightNo\":\"E6 1432\",\"arrival\":\"Ahmedabad (9:35 A.M)\",\"departure\":\"Dubai (5:15 A.M)\",\"passenger\":\"6\",\"baggage\":\"30 kg\",\"fees\":\"\"}]', 'Continental Plan (CP)', '2025-08-28 08:38:29', '2025-08-28 13:50:19', '0e193b51-7011-4438-a873-3689b4c1cd85', '0d88fbdc-1552-4281-a5de-206a35a3f42d', '28082025006_Q01', NULL, NULL),
('5cc74c16-93c5-4c26-a681-1c9a5b19ba69', '25082025004', 'draft', '<ul><li>All Transfers, Sightseeing &amp; Excursion by Air Conditioned vehicle as specified above according to itinerary.</li><li>All Parking, Toll Taxes and driver’s allowances</li><li>Accommodation in Triple Bedded Room&nbsp;on MAP Basis</li></ul>', '<ul><li>Any air/train fare</li><li>Insurance, Guide Services / Boat ride, Entrance fee at monument.</li><li>Expenses of Personal Nature like laundry, telephone calls, room service, alcoholic beverages, mini bar charges, tips, portage, camera fees etc.</li><li>In case of unavailability in the listed hotels, arrangement for an alternate accommodation will be made in a hotel of similar standard.</li><li>Expenses incurred due to mishap, landslide, strikes, political unrest etc. In such cases extra will be charged as per actual</li><li>Personal expenses on items such as Laundry, Soft &amp; Hard Drinks, Bottle Water, Incidentals, Porterage, and Bell-Boy charges, Tips etc.</li><li>Cost of amendment/addition Services in the itinerary.</li><li>Meals other than breakfast unless specified.</li><li>Any puja/ order of Prasad/ Dakhina at any Temples</li><li>Travel Insurance</li><li>NOTE: Anything not in inclusions is excluded</li></ul>', '<p><strong style=\"color: rgb(34, 34, 34);\">Day 1 | (19-10-2025) : Pipariya-Pachmarhi</strong></p><p><br></p><p><span style=\"color: rgb(34, 34, 34);\">Tour starts on arrival at Pipariya station, you will be picked up and drive towards Pachmarh. After reaching check in to your pre-booked hotel and take some rest. Pachmarhi is located at a height of 1,067 feet in a valley of the Satpura Range in Hoshangabad district, also known as Satpuraki Rani. It is a popular hill station of Madhya Pradesh state and is blessed with many beautiful ancient caves and monuments.The rest of the day is free for leisure. Overnight stay Pachmarhi.</span></p><p><br></p><p><strong style=\"color: rgb(34, 34, 34);\">Day 2 | (20-10-2025) : Pachmarhi Sightseeing</strong></p><p><br></p><p><span style=\"color: rgb(34, 34, 34);\">After Breakfast leave for sightseeing HANDI KHO, Gupt Mahadev , Bada Mahadev, Jata Shankar, Priyadarshni,, Lake….etc. Come back &amp; Evening will be for leisure activities., Overnight Stay at Resort.</span></p><p><br></p><p><strong style=\"color: rgb(34, 34, 34);\">Day 3 | (21-10-2025) : Pachmarhi Sightseeing Part 2</strong></p><p><br></p><p><span style=\"color: rgb(34, 34, 34);\">After completion of breakfast, Now Your trip is entirely dedicated to WATER FALLS. This beautiful hill station of Madhya Pradesh is dotted with numerous fantastic places such as : Museum , PANDAV Caves, Bee Falls, Dhupgrh, Reechgarh etc.</span></p><p><br></p><p><strong style=\"color: rgb(34, 34, 34);\">Day 4 | (22-10-2025) : Madhai Safari</strong></p><p><br></p><p><span style=\"color: rgb(34, 34, 34);\">After Breakfast check out to hotel drive to madhai Satpura National Park check in at hotel after freshanup proceed to Afternoon jeep safari in Satpura National Park (Depends on availibilty) Explore the park\'s diverse flora and fauna, including potential tiger sightings. Explore the local area. Back to hotel for dinner and overnight stay in Ma</span></p><p><br></p><p><strong style=\"color: rgb(34, 34, 34);\">Day 5 | (23-10-2025) : Departure Madhai to Pipariya</strong></p><p><br></p><p><span style=\"color: rgb(34, 34, 34);\">﻿Early morning (If time permits) canoe ride on the Denwa River, offering a unique perspective of the park\'s wildlife. Return to Madhai for breakfast. Drive back to Pipariya</span></p>', '<p>NA</p>', '[]', 'American Plan (AP)', '2025-08-25 10:43:34', '2025-08-28 07:00:44', '97cae974-f58a-490f-beb4-1f1579442b89', '0d88fbdc-1552-4281-a5de-206a35a3f42d', '25082025004_Q01', NULL, NULL),
