('9a0b6560-7229-4f06-b857-96bcb028d541', '11042026064', 'draft', NULL, NULL, NULL, NULL, NULL, NULL, '2026-04-11 06:15:13', '2026-04-11 06:15:13', NULL, '74e78145-addf-4775-9806-7d9116108aa5', '11042026064_Q01', NULL, NULL),
('9ae0450b-307a-422d-bece-97b14c01f7e6', '14102025024', 'draft', '<p>Hotel Accommodation</p><p>Air Tickets</p><p>Visa</p><p>All Sightseeing on Private Basis</p><p>All Transfers on Private Basis&nbsp;</p>', '<p><br></p>', '<p><strong>1st Day (Fri, 12 Dec)</strong></p><ul><li>Abu Dhabi Airport to Abu Dhabi Hotel - Arrival - PVT (1-Vehicle 14 Seater)</li></ul><p><br></p><p><strong>2nd Day (Sat, 13 Dec)</strong></p><ul><li>Free Park access at Yas island - Park With Stay at Yas island (5 Adults)</li></ul><p><br></p><p><strong>3rd Day (Sun, 14 Dec)</strong></p><ul><li>Abu Dhabi - Full Day - PVT (1-Vehicle 14 Seater) - Abu dhabi City tour + inter hotel transfer to Dubai Hotel&nbsp;</li></ul><p><br></p><p><strong>4th Day (Mon, 15 Dec)</strong></p><ul><li>Half Day Dubai City Tour - PVT (1-Vehicle (7 Seater)</li><li>Palm Monorail 01 Way - Ticket (5 Adults)</li><li>Dubai Frame Ticket - Ticket (5 Adults)</li><li>Burj khalifa 124th + 125th Non-Prime Hours Tickets (7:30 AM- 11:30 AM) (8:30 PM - 11 PM) - Ticket (5 Adults)</li><li>01 Way Transfer Deira/Bur Dubai to Deira/Bur Dubai - PVT - One Way (1-Vehicle (7 Seater)</li></ul><p><br></p><p><strong>5th Day (Tue, 16 Dec)</strong></p><ul><li>Chysler Limousine - Upto 8 Pax - Ticket (1 Unit)</li><li>View at the Palm Jumeirah Dubai Non-Prime Time (9 AM - 4:30 PM) (7:30 PM) - Ticket (5 Adults)</li><li>Miracle Garden Ticket - Ticket (5 Adults)</li><li>Global Village Ticket - Ticket (5 Adults)</li><li>Miracle Garden + Global - PVT - Three Way (1-Vehicle (7 Seater)</li></ul><p><br></p><p><strong>6th Day (Wed, 17 Dec)</strong></p><ul><li>leisure day - Leisure Day (5 Adults)</li></ul><p><br></p><p><strong>7th Day (Thu, 18 Dec)</strong></p><ul><li>Museum of The Future&nbsp;- Ticket (5 Adults) -&nbsp;<strong>Slots and rates are Subject to availability</strong></li><li>Future Museum From Deira/ Bur Dubai - PVT - Two Way (1-Vehicle (7 Seater))</li><li>Desert Safari Pvt - Ticket (1 Unit)</li><li>Standard Camp - Ticket (5 Adults)</li></ul><p><br></p><p><strong>8th Day (Fri, 19 Dec)</strong></p><ul><li>Marina Dhow Cruise - Ticket (5 Adults)</li><li>Dhow Cruise Marina - PVT - Two Way (1-Vehicle (7 Seater)</li></ul><p><br></p><p><strong>9th Day (Sat, 20 Dec)</strong></p><ul><li>Deira/ Bur Dubai Hotel to fjr Airport - Departure - PVT (1-Vehicle 14 Seater)</li></ul>', '<p><strong>Tourist Visa Charges <u>Rs. 7900</u> Per Person</strong></p><p><br></p><p><strong><u>Documents Required For Tourist Visa&nbsp;</u></strong></p><p>Passport Cover Page Front and Last Banne Jose</p><p>Passport First and Last Page</p><p>Photo</p><p>Pancard</p><p>Aadhar Card</p><p>Hotel</p><p>Air Ticket</p>', '{}', 'Continental Plan (CP)', '2025-11-12 09:37:02', '2025-11-14 11:40:05', '3c98b511-ba3b-48fa-b663-4cb381924222', '0d88fbdc-1552-4281-a5de-206a35a3f42d', '14102025024_Q03', NULL, '{\"1762940275005\":{\"adults\":\"907\",\"extraAdults\":\"618\",\"childWithBed\":\"\",\"childWithoutBed\":\"\",\"childsBelow5\":\"\",\"remarks\":\"Hotel Rates in USD \\nMeal Plan-Room Only\",\"rows\":[{\"key\":\"1762940276971\",\"hotelName\":\"Double Tree by Hilton Abu Dhabi Yas Island Residences - NRF RATES \",\"destination\":\"Abu Dhabi Yas Island\",\"checkIn\":\"2025-12-12\",\"checkOut\":\"2025-12-14\",\"roomCategory\":\"2 King One bedroom Apartment with 2 parks  4 Pax + 1 Adult with Extra Bed/Mattress\",\"noOfRooms\":\"2\"}]},\"1762940304711\":{\"adults\":\"948\",\"extraAdults\":\"656\",\"childWithBed\":\"\",\"childWithoutBed\":\"\",\"childsBelow5\":\"\",\"remarks\":\"Hotel Rates in USD \\nMeal Plan-Breakfast Only\",\"rows\":[{\"key\":\"1762940861564\",\"hotelName\":\"Yas Plaza Circuit Hotel, Abu Dhabi Yas Island - NRF RATES \",\"destination\":\"Abu Dhabi Yas Island\",\"checkIn\":\"2025-12-12\",\"checkOut\":\"2025-12-14\",\"roomCategory\":\"2 Queen Deluxe Family Room Plaza View Sofa Bed with 2 park access  4 Pax + 1 Adult with Extra Bed/Mattress\",\"noOfRooms\":\"2\"}]}}'),
('a03b64e3-2c3c-4732-b58b-80f86c61bc35', NULL, 'Sent', '<ul><li>Accommodation on twin sharing basis in the food plan stated above.</li><li>All transfers and sightseeing arrangements by&nbsp;<strong>Innova 7+1 - AC</strong>&nbsp;Vehicle as per itinerary.</li><li>Vehicle at your disposal as per the itinerary.</li><li>Driver Allowance, toll, parking fee, Night halt charges, inter- state permit and govt. applicable service tax.</li><li>All applicable taxes.</li></ul><p><br></p>', '<ul><li>Any other services or food which is not mentioned in the above \'Includes\' section.</li><li>Expense of personal nature such as room service and special orders, alcoholic and non alcoholic beverages, porterage, tips, laundry, telephones, beverages etc</li><li>Entry Tickets / Entrance fees in all sightseeing places to be visited as per itinerary.</li><li>Optional, suggested or unspecified activities.</li><li>Any Air, Train, Bus or Cruise fare from / to your originating city of stay, unless specified.</li><li>Any transport services to or from your originating place to Ex hub as per itinerary.</li><li>Any extra excursions or sightseeing apart from the above specified itinerary.</li><li>Any extra cost incurred due to illness, accident, hospitalization or any personal emergency.</li><li><strong>Kanyakumari Sightseeing.</strong></li></ul><p><br></p>', '<p><strong>Day 1 : Cochin (arrival At Cochin)</strong></p><p>Upon arrival our Driver will greet you at Cochin Airport/Railway Station. Later on proceed to Cochin &amp; Check- in at the hotel and relax for a while amidst the comforts of your room. Later proceed to sightseeing. Visit Dutch Palace (Closed on Fridays), Jewish Synagogue (Closed on Saturdays and Jewish holidays), St. Francis church, Santa Cruz basilica, Chinese Fishing Nets as time permits. Overnight stay at the Hotel/Resort.</p><p><strong>Day 2 : Munnar</strong></p><p>Enjoy your breakfast with the new sunrise. Later on proceed to Munnar. On the way visit Neriyamangalam Bridge, Cheeyyapara water falls, Vallara water falls, Kallar water falls. Later Check- in at the hotel and relax for a while amidst the comforts of your room. Later Visit Blossom Garden. Explore the rest of the day at your own leisure. Overnight stay at the Hotel/Resort.</p><p><strong>Day 3 : Munnar Ss</strong></p><p>Enjoy Your Breakfast With The New Sunrise. Later Visit Tea Museum. Then To Rajamala (ervikulam National Park) - House Of The Highly Endangered Mountain Goats - The Nilgiri Thars. Then To Echo Point And Mattupetty Dam. Speed Boating Facilities Are Available Here By Extra Cost. The Dam Is Flanked By Forests And Vast Expanse Of Grass Land On One Side And The Kundala Dam, Tea Plantation On The Other Etc… Overnight Stay At The Hotel/resort. Note : The Eravikulam National Park (ENP), the natural habitat of the Nilgiri tahr, will be closed for the calving season of the species from February 1 to March 31.</p><p><strong>Day 4 : Thekkady</strong></p><p>Enjoy your breakfast with the new sunrise. Later on proceed to Thekkady &amp; Check- in at the hotel and relax for a while amidst the comforts of your room. Later visit Periyar wild life sanctuary. Periyar Lake around which the sanctuary is built, for boating. This is the only sanctuary in India where you can have the unique experience of viewing the wild life at close quarters from the safety of boat. Overnight stay at the Hotel/Resort. Optional activities by extra cost (you can book in advance)&nbsp;<a href=\"https://www.periyarfoundation.online/\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"color: rgb(17, 85, 204);\">https://www.periyarfoundation.online/</a>&nbsp;<a href=\"https://www.periyartigerreserve.org/\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"color: rgb(17, 85, 204);\">https://www.periyartigerreserve.org/</a>&nbsp;Bamboo rafting, Natural walk, Gavi jeep safari, Village safari</p><p><strong>Day 5 : Kovalam</strong></p><p>Enjoy your breakfast with the new sunrise. Later on proceed to Kovalam &amp; Check- in at the hotel and relax for a while amidst the comforts of your room. Kovalam - breathtakingly beautiful - a haven of peace and tranquility - the idyllic tourist destination in God\'s own country. Kovalam offers an excellent diversity with Kovalam beach to suit all desires and occasions. Visit light house beach and Hawah beach. Overnight stay at the Hotel/Resort.</p><p><strong>Day 6 : Trivandrum Ss</strong></p><p>Enjoy your breakfast with the new sunrise. Later on proceed to Trivandrum for city tour covering Napier Museum, Sri Padmanabha Swami Temple., and Zoo. Overnight stay at the Hotel/Resort.</p><p><strong>Day 7 : Alleppey</strong></p><p>Enjoy your breakfast with the new sunrise. Later on proceed to Alleppey. The \"Venice of India\" noted for its winding waterways and canals. &amp; Check- in at the hotel and relax for a while amidst the comforts of your room. Explore the natural beauty of Kerala, the paddy fields, narrow canals, coir villages etc. Overnight stay at the Hotel/Resort.</p><p><strong>Day 8 : Departure Transfer</strong></p><p>Enjoy your breakfast with the new sunrise. Then after transfer to Airport / Railway station for departure. Back to home with sweet memories of your tour.</p>', NULL, '[{\"key\": 1754401540221, \"fees\": \"12170\", \"arrival\": \"MUMBAI\", \"baggage\": \"15KG\", \"flightNo\": \"AI 2540\", \"departure\": \"AHMEDABAD\", \"passenger\": \"4\", \"journeyDate\": \"2025-10-19\"}, {\"key\": 1754401679227, \"fees\": \"\", \"arrival\": \"COCHIN\", \"baggage\": \"15KG\", \"flightNo\": \"AI 2517\", \"departure\": \"MUMBAI\", \"passenger\": \"4\", \"journeyDate\": \"2025-10-19\"}, {\"key\": 1754401714210, \"fees\": \"15199\", \"arrival\": \"AHMEDABAD\", \"baggage\": \"15KG\", \"flightNo\": \"6E 6392\", \"departure\": \"COCHIN\", \"passenger\": \"4\", \"journeyDate\": \"2025-10-26\"}]', 'Modified American Plan (MAP)', '2025-08-05 11:03:30', '2025-08-05 14:04:01', NULL, '0d88fbdc-1552-4281-a5de-206a35a3f42d', NULL, NULL, NULL),
