('b7051271-ccde-48e1-a9ee-f83f2f2189ac', '31122025035', 'draft', '<p>Hotel Accommodation</p><p>Meals</p><p>Sightseeing</p>', '<p>Ait ticket</p><p>visa</p><p>Insurance</p>', '<p>Day 1: Arrival</p><p>Day 2 : Sightseeing</p><p>Day 3 : Sightseeing</p><p>Day 4 : Sightseeing</p><p>Day 5 : Sightseeing</p><p>Day 6 : Departure</p>', '<p>Visa charges : 8000</p>', '{\"1770272711296\":{\"ratePerPerson\":\"26900\",\"remarks\":\"asdasd\",\"rows\":[{\"key\":\"1770272714015\",\"travelDate\":\"2026-02-27\",\"flightNo\":\"A120\",\"departure\":\"AMD\",\"arrival\":\"DXB\",\"departureTime\":\"14:25\",\"arrivalTime\":\"10:02\",\"passenger\":\"02\",\"baggage\":\"20\"}]}}', 'Continental Plan (CP)', '2025-12-31 06:29:39', '2026-03-11 08:10:16', NULL, '0cae09bb-571c-4816-bf1b-bab379e7a682', '31122025035_Q01', NULL, '{\"1770272820550\":{\"adults\":\"86000\",\"extraAdults\":\"25000\",\"childWithBed\":\"\",\"childWithoutBed\":\"\",\"childsBelow5\":\"\",\"remarks\":\"asdas\",\"rows\":[{\"key\":\"1770272822366\",\"hotelName\":\"Jacob\'s \",\"destination\":\"Dubai\",\"checkIn\":\"2026-02-27\",\"checkOut\":\"2026-03-03\",\"roomCategory\":\"standard\",\"noOfRooms\":\"01\"}]}}'),
('b95d94a4-afc8-4776-9a20-915c63c6adcf', '14102025023', 'draft', '<p>Hotel Accommodation</p><p>Air Tickets</p><p>Visa</p><p>All Sightseeing on Private Basis</p><p>All Transfers on Private Basis</p>', '<p>Except Not Mention in Itinerary and Inclusions !!!</p>', '<p><strong>1st Day (Tue, 4 Nov)</strong></p><ul><li>DXB Airport to Deira/ Bur Dubai Hotel - Arrival - PVT (1-Vehicle (7 Seater))</li></ul><p><br></p><p><strong>2nd Day (Wed, 5 Nov)</strong></p><ul><li>Half Day Dubai City Tour - PVT (1-Vehicle (7 Seater))</li><li>Palm Monorail 01 Way - Ticket (2Ad. + 1Ch.)</li><li>View at the Palm Jumeirah Dubai Non-Prime Time (9 AM - 4:30 PM) (7:30 PM) - Ticket (2Ad. + 1Ch.)</li><li>View At Palm - PVT - Two Way (1-Vehicle (7 Seater))</li><li>Burj khalifa 124th + 125th Non-Prime Hours Tickets (7:30 AM- 11:30 AM) (8:30 PM - 11 PM) - Ticket (3 Adults)</li></ul><p><br></p><p><strong>3rd Day (Thu, 6 Nov)</strong></p><ul><li>Miracle Garden + Global - PVT - Three Way (1-Vehicle (7 Seater))</li><li>Global Village Ticket - Ticket (2Ad. + 1Ch.)</li><li>Miracle Garden Ticket - Ticket (2Ad. + 1Ch.)</li></ul><p><br></p><p><strong>4th Day (Fri, 7 Nov)</strong></p><ul><li>Dubai Frame From Deira/ Bur Dubai - PVT - Two Way (1-Vehicle (7 Seater))</li><li>Dubai Frame Ticket - Ticket (2Ad. + 1Ch.)</li><li>Desert Safari Pvt - Ticket (1 Unit)</li><li>Standard Lama Camp - Ticket (2Ad. + 1Ch.)</li></ul><p><br></p><p><strong>5th Day (Sat, 8 Nov)</strong></p><ul><li>01 Way Transfer Deira/Bur Dubai to Deira/Bur Dubai - PVT - One Way (1-Vehicle (7 Seater))</li><li>Museum of The Future (B2B) - Ticket (2Ad. + 1Ch.)</li><li>Chysler Limousine - Upto 8 Pax - Ticket (1 Unit)</li><li>Dhow Cruise Marina - PVT - Two Way (1-Vehicle (7 Seater))</li><li>Marina Dhow Cruise - Ticket (2Ad. + 1Ch.)</li></ul><p><br></p><p><strong>6th Day (Sun, 9 Nov)</strong></p><ul><li>Abu Dhabi - Full Day - PVT (1-Vehicle (7 Seater))</li></ul><p><br></p><p><strong>7th Day (Mon, 10 Nov)</strong></p><ul><li>Free Park access at Yas island - Park With Stay at Yas island (2Ad. + 1Ch.)</li><li>Abu Dhabi Hotel to Abu Dhabi Airport - Departure - PVT (1-Vehicle (7 Seater))</li></ul>', '<p><strong><u>Tourist Visa Charges Rs. 7800 Per Person</u></strong></p><p><br></p><p><strong><u>Documents Required For Tourist Visa</u></strong></p><p><br></p><p>Passport Cover Page Front and Last Banne Jose</p><p>Passport First and Last Page</p><p>Photo</p><p>Pancard</p><p>Aadhar Card</p><p>Hotel</p><p>Ticket</p>', '{\"1760511981386\":{\"ratePerPerson\":\"30350\",\"remarks\":\"\",\"rows\":[{\"key\":\"1760512392516\",\"travelDate\":\"2025-11-04\",\"flightNo\":\"FZ 438\",\"departure\":\"Ahmedabad\",\"arrival\":\"Dubai\",\"departureTime\":\"03:40\",\"arrivalTime\":\"05:25\",\"passenger\":\"3\",\"baggage\":\"30\"},{\"key\":\"1760512470350\",\"travelDate\":\"2025-11-10\",\"flightNo\":\"6E 1478\",\"departure\":\"Dubai\",\"arrival\":\"Ahmedabad\",\"departureTime\":\"05:15\",\"arrivalTime\":\"09:20\",\"passenger\":\"3\",\"baggage\":\"30\"}]}}', 'Continental Plan (CP)', '2025-10-14 12:08:54', '2025-10-15 07:27:43', '94214f49-8615-4616-88a6-299754454cc0', '0d88fbdc-1552-4281-a5de-206a35a3f42d', '14102025023_Q01', NULL, '{\"1760511992685\":{\"adults\":\"1027\",\"extraAdults\":\"\",\"childWithBed\":\"777\",\"childWithoutBed\":\"\",\"childsBelow5\":\"\",\"remarks\":\"All Package Rates in USD\\n\\n\",\"rows\":[{\"key\":\"1760512003504\",\"hotelName\":\"Majestic Premier 4*\",\"destination\":\"Bur Dubai\",\"checkIn\":\"2025-11-04\",\"checkOut\":\"2025-09-08\",\"roomCategory\":\"Classic Room\",\"noOfRooms\":\"1\"},{\"key\":\"1760512008983\",\"hotelName\":\"Radisson Blu Hotel, Abu Dhabi Yas Island 4*\",\"destination\":\"Abu Dhabi Yas Island\",\"checkIn\":\"2025-11-08\",\"checkOut\":\"2025-11-09\",\"roomCategory\":\"Standard Room\",\"noOfRooms\":\"1\"}]}}'),
