('bc4a84e1-e134-4424-9de5-65870b191570', '17092025020', 'draft', '<ul><li><strong>5 NIGHT STAY AT </strong><strong style=\"color: rgb(36, 36, 36);\">SAVOY CREST HOTEL </strong><strong style=\"color: rgb(36, 36, 36); background-color: rgb(255, 255, 0);\">WITH BREAKFAST</strong><strong style=\"color: rgb(36, 36, 36);\">.</strong></li><li><strong>2 NIGHT STAY AT CROWN PLAZA ABU DHABHI-YASH ISLAND </strong><strong style=\"background-color: rgb(255, 255, 0);\">WITH BREAKFAST</strong><strong>. </strong></li><li><strong>ALL SIGHT SEEN AS PER ITINERARY.</strong></li><li><strong>ALL TOURS AND TRANSFER </strong><strong style=\"background-color: rgb(255, 255, 0);\">ARE BASED ON PVT.</strong></li></ul>', '<ul><li><strong>Tourism Dirham if not mentioned in the inclusions&nbsp;</strong></li><li><strong>Visa &amp; Insurance if not mentioned in the inclusions&nbsp;</strong></li><li><strong>OTB is not included in the package. (It depends upon the airline)&nbsp;</strong></li><li><strong>Any expense of personal nature not mentioned in the inclusions&nbsp;</strong></li><li><strong>Tips / Gratuities&nbsp;</strong></li></ul>', '<h2><strong style=\"color: rgb(36, 36, 36);\">DAY 1</strong></h2><ul><li><strong>Airport Transfer</strong>&nbsp;from DUBAI INTERNATIONAL AIRPORT T1/T2/T3</li><li><strong>Marina Dhow Cruise Dinner - Standard&nbsp;</strong>:&nbsp;<span style=\"color: rgb(13, 13, 13);\">A relaxing cruise with the view of sky scrapers of Dubai Marina with lavish buffet dinner and entertainment show on board</span></li></ul><h2><strong style=\"color: rgb(36, 36, 36);\">DAY 2</strong></h2><ul><li><strong>Dubai Half Day City Tour - 5 Hour (Private)</strong>&nbsp;: Experience panoramic half day city tour of Dubai and enjoy Old and New Dubai sightseeing.</li><li><strong>Monorail Ticket&nbsp;</strong>:&nbsp;<span style=\"color: rgb(13, 13, 13);\">The most iconic way to navigate across the Palm Jumeirah. It is not a mere form of transportation; it\'s an experiential journey.</span></li><li><strong>Standard Dubai Desert Safari 4X4 with Camel Ride, BBQ Dinner, Belly Dance show (Private)</strong>&nbsp;: Enjoy Magical &amp; Memorable Evening with Dune Bashing, BBQ Dinner and Entertainment Shows</li></ul><h2><strong style=\"color: rgb(36, 36, 36);\">DAY 3</strong></h2><ul><li><strong>Dubai Frame&nbsp;</strong>:&nbsp;<strong>:&nbsp;</strong>An architectural landmark which holds the record for the largest frame in the world</li><li><strong>Museum of the Future&nbsp;</strong>: The Museum of the Future is an exhibition space for innovative and futuristic ideologies, services, and products&nbsp;<strong style=\"color: rgb(192, 57, 43);\"><em>(Subject to availability at time of booking)</em></strong></li><li><strong>At the top burj khalifa - 124th floor Non-Prime&nbsp;</strong>: The tallest structure and building in the world:&nbsp;&nbsp;And enjoy shopping at Dubai Mall; But not to miss the fascinating Fountain Show</li></ul><h2><strong style=\"color: rgb(36, 36, 36);\">DAY 4</strong></h2><ul><li><strong>The View at the Palm Non-prime&nbsp;</strong>: Enjoy incomparable views of one of Dubai’s most talked about landmarks at The View at The Palm.</li><li><strong>Miracle Garden&nbsp;</strong>:&nbsp;<span style=\"color: rgb(13, 13, 13);\">World\'s largest natural flower garden, featuring over 50 million flowers and 250 million plants.&nbsp;</span></li><li><strong>Global Village&nbsp;</strong>:&nbsp;<span style=\"color: rgb(13, 13, 13);\">World\'s largest tourism, leisure, shopping and entertainment project by combining cultures of 90 countries</span></li></ul><p><span style=\"color: rgb(13, 13, 13);\">﻿</span></p><h2><strong style=\"color: rgb(36, 36, 36);\">DAY 5</strong></h2><ul><li><strong>Atlantis Aquaventure water park + Lost chamber&nbsp;</strong>: World\'s largest waterpark promises a world of excitement to make you feel #DifferentInWater in more ways than one . Atlantis-themed aquarium with underwater halls &amp; tunnels housing marine life, plus feeding sessions.</li></ul><h2><strong style=\"color: rgb(36, 36, 36);\">DAY 6</strong></h2><ul><li><strong>Full Day Abu Dhabi City Tour - 10 Hour (Private)</strong>&nbsp;: Discover the rich heritage and modern marvels of the UAE’s capital with our immersive Abu Dhabi City Tour &amp; drop to Abu Dhabi Hotel&nbsp;&nbsp;</li><li><strong>BAPS Hindu Mandir, Abu Dhabi&nbsp;</strong>: Entry to BAPS Temple Abu Dhabi&nbsp;</li><li><strong>Grand Mosque Entry Ticket&nbsp;</strong>: Entry for Grand mosque Abu Dhabi</li></ul><h2><strong>DAY 7</strong></h2><ul><li><strong>Day at Yas Island</strong></li></ul><h2><strong>DAY 8</strong></h2><ul><li><strong>Airport Transfer</strong>&nbsp;to DUBAI INTERNATIONAL AIRPORT T1/T2/T3</li></ul>', '<h2><strong style=\"background-color: rgb(255, 255, 0);\">VISA CHARGES 7500/- INR PER PERSON</strong></h2><p><br></p><h2>VISA DOCCUMENT LIST :</h2><ul><li><strong>Hotel Booking</strong></li><li><strong>Passport</strong></li><li><strong>Passport Back</strong></li><li><strong>Round Trip Flight Ticket</strong></li><li><strong>Traveler Photo</strong></li><li><strong>Pan Card</strong></li></ul>', '{\"1758193277835\":{\"ratePerPerson\":\"54826\",\"remarks\":\"\",\"rows\":[{\"key\":\"1758193280165\",\"travelDate\":\"2025-10-17\",\"flightNo\":\"EK 539\",\"departure\":\"AHMEDABAD\",\"arrival\":\"DUBAI\",\"departureTime\":\"04:35\",\"arrivalTime\":\"06:10\",\"passenger\":\"6\",\"baggage\":\"30\"},{\"key\":\"1758193298415\",\"travelDate\":\"2025-09-25\",\"flightNo\":\"EK  540\",\"departure\":\"DUBAI\",\"arrival\":\"AHMEDABAD\",\"departureTime\":\"03:50\",\"arrivalTime\":\"08:10\",\"passenger\":\"6\",\"baggage\":\"30\"}]}}', 'Continental Plan (CP)', '2025-09-17 06:23:28', '2025-09-18 11:49:41', 'c64a5b8a-f1ff-4db2-844f-0b1165abb212', '74e78145-addf-4775-9806-7d9116108aa5', '17092025020_Q01', NULL, '{\"1758182556380\":{\"adults\":\"982\",\"extraAdults\":\"\",\"childWithBed\":\"663\",\"childWithoutBed\":\"663\",\"childsBelow5\":\"\",\"remarks\":\"PROVIDED RATES ARE BASED ON USD.\",\"rows\":[{\"key\":\"1758182560751\",\"hotelName\":\"Savoy Crest Hotel Apartments\",\"destination\":\"DUBAI\",\"checkIn\":\"2025-09-17\",\"checkOut\":\"2025-09-22\",\"roomCategory\":\"STUDIO ROOM with Bed\",\"noOfRooms\":\"2\"},{\"key\":\"1758187336862\",\"hotelName\":\"Crowne Plaza Abu Dhabi - Yas Island \",\"destination\":\"ABU DHABI\",\"checkIn\":\"2025-10-22\",\"checkOut\":\"2025-09-24\",\"roomCategory\":\"STANDARD ROOM with Bed & Breakfast\",\"noOfRooms\":\"2\"}]}}'),
('c23912f0-bfe0-437a-9168-3beaf4361a42', '27102025025', 'draft', '<ul><li>Transfer ( HKT APT -HKT HTL -KBV HTL-KBV APT ) with PVT by sedan car</li><li>Transfer ( BKK APT -BKK HTL-BKK APT ) with PVT by sedan car</li><li>Hotel Accommodation with Break Fast</li><li>Air Ticket</li><li>Visa</li><li>All Transfer on SIC Basis</li></ul>', '<p><br></p>', '<ul><li><span style=\"color: rgb(0, 0, 0);\">Phi Phi Island Tour&nbsp;by Speed Boat Khai Island&nbsp;+ Local Lunch + Transfer on SIC</span><strong>&nbsp;(Excl Mandatory National Park Fee THB 400 PP)</strong></li><li><span style=\"color: rgb(0, 0, 0);\">Full Day James Bond Island Tour by speed Boat + Sea Canoe with Lunch EXCLUDE. National Marine Park FEE THB 300 PP -on SIC\'</span></li><li><span style=\"color: rgb(0, 0, 0);\">Phuket Half Day City Tour with guide&nbsp;+ Tiger Park (Smallest Tiger) with PVT Enroute to krabi hotel</span></li><li><span style=\"color: rgb(0, 0, 0);\">4 island tour by Speedboat with local Thai Lunch on SIC&nbsp;</span>(EXCL Mandatory NPF FEE THB 200 PP)</li><li><span style=\"color: rgb(0, 0, 0);\">Half day BKK Temple &amp; City Tour&nbsp;</span><strong>with Guide</strong>&nbsp;(Golden Buddha + MINI Reclining Buddha+ Gems Gallery) with Pvt&nbsp;<strong>Enroute to bangkok hotel</strong></li><li><span style=\"color: rgb(0, 0, 0);\">Full Day Safari World + Marine Park with Lunch on SIC (Monday closed)</span></li></ul>', '<ul><li>Please Apply Your Digital Arrival Card Before Traveling</li></ul>', '{\"1761656779102\":{\"ratePerPerson\":\"21046\",\"remarks\":\"\",\"rows\":[{\"key\":\"1761656781260\",\"travelDate\":\"2025-11-22\",\"flightNo\":\"6E 1089\",\"departure\":\"MUMBAI\",\"arrival\":\"PHUKET\",\"departureTime\":\"15:50\",\"arrivalTime\":\"21:45\",\"passenger\":\"2\",\"baggage\":\"20\"},{\"key\":\"1761657178996\",\"travelDate\":\"2025-11-29\",\"flightNo\":\"6E 1052\",\"departure\":\"BANGKOK\",\"arrival\":\"MUMBAI\",\"departureTime\":\"22:10\",\"arrivalTime\":\"13:45\",\"passenger\":\"2\",\"baggage\