('d5eee820-b0d7-46fb-b25c-358d8b38c612', NULL, 'Sent', '<ol><li>Airport pickup and drop-off (AC vehicle).</li><li>Accommodation in 3/4/5-star hotels (as per package).</li><li>Daily buffet breakfast.</li><li>Guided sightseeing tours with a professional guide.</li><li>Entrance fees to major attractions (as per itinerary).</li><li>Comfortable AC transportation for all transfers and tours.</li><li>Complimentary welcome drink on arrival.</li><li>Travel insurance (basic coverage).</li><li>All applicable taxes and service charges.</li><li>24/7 customer support during the trip.</li></ol>', '<ol><li>Airfare/Train tickets (unless mentioned).</li><li>Visa and immigration fees (if applicable).</li><li>Meals other than those specified in inclusions.</li><li>Personal expenses (shopping, telephone, laundry, etc.).</li><li>Optional tours or activities not listed in the itinerary.</li><li>Travel insurance (if not opted for).</li><li>Early check-in or late check-out charges.</li><li>Tips to guides, drivers, and hotel staff.</li><li>Medical expenses or emergency evacuation.</li><li>Any costs due to unforeseen circumstances (weather, strikes, etc.).</li></ol>', '<p><strong>Day 1</strong></p><p>Arrival at destination, hotel check-in, welcome drink, and leisure evening.</p><p><strong>Day 2</strong></p><p>City tour – Visit historical monuments, museums, and local markets.</p><p><strong>Day 3</strong></p><p>Excursion to nearby scenic spot (beach/mountain/lake) + adventure activity.</p><p><strong>Day 4</strong></p><p>Cultural experience – Attend local festival/show, enjoy traditional cuisine.</p><p><strong>Day 5</strong></p><p>Shopping at famous markets, optional spa session, and departure transfer.</p><p><strong>Day 6</strong></p><p>Explore iconic landmarks and enjoy a panoramic city view.</p><p><strong>Day 7</strong></p><p>Day trip to a nearby UNESCO heritage site.</p><p><strong>Day 8</strong></p><p>Leisure day for self-exploration or optional tours.</p><p><strong>Day 9</strong></p><p>Visit amusement park/water park or wildlife sanctuary.</p><p><strong>Day 10</strong></p><p>Final day relaxation and return journey.</p>', '<ol><li><strong>Visa fee charges</strong> (to be paid directly to the embassy/consulate).</li><li><strong>Visa rejection fees</strong> (non-refundable in case of refusal).</li><li><strong>Fast-track or express visa processing fees.</strong></li><li><strong>Courier charges</strong> for sending or receiving documents.</li><li><strong>Cost of additional documents</strong> (affidavits, notarization, etc.).</li><li><strong>Interview appointment fees</strong> (if applicable).</li><li><strong>Biometric registration charges</strong> (if required separately).</li><li><strong>Visa reapplication costs</strong> (if initial visa is rejected).</li><li><strong>Travel expenses to/from the embassy or visa center.</strong></li><li><strong>Penalties for late submission</strong> of documents or incorrect details.</li></ol>', '[{\"key\": 1753699115342, \"fees\": \"Maiores sed magna qu\", \"arrival\": \"Doloremque incididun\", \"baggage\": \"Labore repellendus \", \"flightNo\": \"Aut magna tempore e\", \"departure\": \"Minima possimus nih\", \"passenger\": \"Et qui maxime praese\", \"journeyDate\": \"1982-12-07\"}, {\"key\": 1753699115772, \"fees\": \"Culpa incididunt cor\", \"arrival\": \"Omnis obcaecati mini\", \"baggage\": \"Ea et eum rem quas u\", \"flightNo\": \"Pariatur Eveniet p\", \"departure\": \"Sed fugiat deserunt\", \"passenger\": \"Voluptatem incidunt\", \"journeyDate\": \"2009-07-27\"}, {\"key\": 1753699116021, \"fees\": \"Pariatur Excepteur \", \"arrival\": \"Voluptatibus ut cons\", \"baggage\": \"Dolor atque consequu\", \"flightNo\": \"Quisquam elit paria\", \"departure\": \"Qui praesentium beat\", \"passenger\": \"Ipsa voluptates rei\", \"journeyDate\": \"2011-06-08\"}]', 'American Plan (AP)', '2025-07-28 08:59:38', '2025-07-29 08:15:41', NULL, NULL, NULL, NULL, NULL),
