('d63d5c70-0577-468a-924f-c78241612a97', '09032026045', 'draft', NULL, NULL, NULL, NULL, '{}', NULL, '2026-03-13 08:09:13', '2026-03-13 08:09:13', NULL, '74e78145-addf-4775-9806-7d9116108aa5', '09032026045_Q03', NULL, NULL),
('d699a4fa-d88a-4cc9-8c82-47dc7525f49b', '30102025027', 'draft', '<p>●&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<strong>3</strong>&nbsp;<strong>Nights</strong>&nbsp;stay at selected category of hotel at&nbsp;<strong>Port Blair</strong>&nbsp;+&nbsp;<strong>2&nbsp;Nights</strong>&nbsp;stay at selected category of hotel at&nbsp;<strong>Havelock</strong>&nbsp;+&nbsp;<strong>1</strong>&nbsp;<strong>Night</strong>&nbsp;stay at selected category of hotel at&nbsp;<strong>Neil Island</strong></p><p>●&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Daily&nbsp;<strong>breakfast&nbsp;</strong>on a set menu or buffet basis, as indicated in the meal plan (Except breakfast on day of arrival).</p><p>●&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Entry tickets to all sightseeing places as per the itinerary.&nbsp;</p><p>●&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Private Ferry Tickets (Base Category): Port Blair - Havelock&nbsp;+&nbsp;Havelock - Neil&nbsp;+&nbsp;Neil - Port Blair&nbsp;<strong>(Makruzz / Nautika / ITT Majestic subject to availability)</strong></p><p>●&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;All transfers by&nbsp;<strong>1 AC Car</strong>&nbsp;in Port Blair/ Havelock/ Neil&nbsp;<strong>(We provide AC Xylos / Ertiga at Port Blair and Havelock)&nbsp;</strong>on point-to-point basis only.</p><p>●&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Excursion to Elephant Beach subject to weather conditions.</p><p>●&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<strong>Complimentary:</strong>&nbsp;Few mins of snorkeling at Elephant Beach (Provided by Association, if not provided no refund).</p><p>●&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<strong>Complimentary:&nbsp;&nbsp;</strong>1 pint of&nbsp;<strong style=\"color: red;\"><u>domestic beer or 1 glass of mocktail will be provided complimentary per person</u></strong><u style=\"color: red;\">&nbsp;</u>at&nbsp;<strong style=\"color: red;\">Something Different – A Beachside Café</strong><span style=\"color: red;\">&nbsp;</span>only enroute from Elephant Beach to Hotel. Children’s drinks are non-transferrable. Offer is valid only on the mentioned drinks and only on day when guest have Elephant Beach and for lunch only. Please note this is a complimentary add on. If the guest does not avail the same there shall be no refund.</p><p>●&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Meet and Greet Service at Airport</p><p>●&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Tour Manager briefing every evening at Port Blair and Havelock.</p><p><br></p>', '<p>●&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Vehicle at disposal.</p><p>●&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Early check in or late check out.</p><p>●&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Any personal expenses such as room service and special orders of Alcoholic and non-alcoholic beverages.</p><p>●&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Water Sports.</p><p>●&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Any extra excursions or sightseeing apart from the suggested tour itinerary.</p><p>●&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Porter Charges, Camera Ticket charges and Guide Charges including Cellular Jail &amp; Ross Island.</p><p>●&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Anything not mentioned in inclusions.</p><p>●&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Honeymoon Delights – Refer to attached sheet for supplements</p>', '<p><strong style=\"color: black;\">Day 1</strong></p><p><strong style=\"color: black;\">Land at Port Blair - Corbyn\'s Cove Beach + Cellular Jail + Sound &amp; Light Show at Cellular Jail</strong></p><p><br></p><p>Land at Port Blair airport in the&nbsp;<u>morning or afternoon</u>&nbsp;and transfer to&nbsp;<u>hotel</u>. Proceed for a quick visit to&nbsp;<strong><u>Corbyn\'s Cove Beach,</u></strong>&nbsp;the only beach in Port Blair where you can swim, relax and unwind. Guests can enjoy some water-sport activities like Jet-Ski, Parasailing, Sea-Kart, Speed Boat rides, etc. on direct payment basis and then proceed to visit the famous&nbsp;<strong><u>Cellular Jail,</u></strong>&nbsp;(entry closes at 1545hrs), an old colonial prison situated in Port Blair also known as \'Kalapani\'. Later, attend the enthralling&nbsp;<strong><u>Sound &amp; Light Show at Cellular Jail</u></strong>&nbsp;where the heroic saga of the Indian freedom struggle is brought alive and then drop back to hotel.</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;In case your flight lands in the afternoon, we may offer to take you direct from the airport to Cellular Jail so that you are able to watch the Sound &amp; Light show.</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;If your hotel is located at Wandoor or Chidyatapu, we will first take you to Cellular Jail and then drop you to the hotel.</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Please note that the Sound &amp; Light show timing is subject to ticket availability&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Please note that since vehicles are not allowed to wait outside Cellular Jail, all guests will be dropped at the parking point (approximately 400mtrs from the entry gate of the Jail) and will have to walk from the parking point until the entrance. Once the Jail visit or Sound &amp; Light show is done, the guest will have to walk back to the parking point to board the vehicle.</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Beaches close by sunset or by 1730hrs, whichever is earlier.</p><p>Corbyns Cove Beach visit is subject to weather conditions &amp; flight landing time at Port Blair.<em>&nbsp;</em></p><p><br></p><p><strong style=\"color: black;\">Day 2</strong></p><p><strong style=\"color: black;\">Port Blair - North Bay &amp; Ross Island (Netaji Subhash Chandra Bose Island)</strong></p><p>Today after breakfast, proceed for a full-day excursion to&nbsp;<strong>North Bay Island</strong>&nbsp;(Coral Island) by sharing boats. The same boat will then take the guest to&nbsp;visit<strong>&nbsp;Ross Island (Netaji Subhash Chandra Bose Island)&nbsp;</strong>that was named after Mr. Daniel Ross, a famous marine surveyor. In December 2018, it was renamed as Netaji Subhash Chandra Bose Island. Drop back to hotel and evening at Leisure.</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Ferry for North Bay trip leaves at fixed timings please ensure you are on time at Water Sports Complex from where you will board the boat</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;All activities are at an extra cost at North Bay</p><p>The last ferry for Ross Island (Netaji Subhash Chandra Bose Island) leaves by 1400hrs.</p><p><br></p><p><strong style=\"color: black;\">Day 3</strong></p><p><strong style=\"color: black;\">Port Blair - Havelock (Swaraj Dweep) - Afternoon visit to Beach No 7</strong></p><p>Departure by&nbsp;morning or afternoon&nbsp;<strong>Private ferry (PB- HL)&nbsp;-&nbsp;</strong>Journey time is 1.5 / 2.5 hrs. On arrival at Havelock (Swaraj Dweep),&nbsp;our team will meet the guest at the exit gate and then the guest will be dropped to their havelock hotel. At around 1430hrs - 1530hrs, proceed to Beach No. 7 (Radhanagar Beach) rated as the ‘Best Beach in Asia’ by Time Magazine to unwind, relax and enjoy the pristine white sand beach. Later drop back to the hotel. Evening at leisure.</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Kindly remind the Port Blair hotel to provide packed breakfast since the same is not included at Havelock (Swaraj Dweep)</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Kindly carry a valid PHOTO ID&nbsp;<strong>(Pan Card not accepted)</strong>&nbsp;to enter the Port Blair jetty. Alcohol cannot be carried on-board the ferry.</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Beach No 7 is closed for guests after sunset.</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Cars are limited on Havelock Island (Swaraj Dweep) and hence guests are requested to kindly adhere to the timelines as shared by the tour manager.</p><p><br></p><p><strong style=\"color: black;\">Day 4</strong></p><p><strong style=\"color: black;\">Havelock (Swaraj Dweep)&nbsp;- Elephant Beach&nbsp;(Complimentary Beer or Mocktail at Something Different)</strong></p><p>  &nbsp;Embark on the most memorable excursion to<strong>&nbsp;Elephant Beach&nbsp;</strong>by sharing boat. The&nbsp;<strong>journey time is 30-45&nbsp;</strong>mins and you can also opt for some water sports activities like Snorkeling, Sea Walk, Jet Ski, Glass bottom Boat, Banana Boat Ride, Sofa boat ride, Parasailing, etc. on direct payment.<strong>&nbsp;</strong><em><u>It is advisable to pre book activity at the boarding point itself to avoid missing out on these activities, our tour manager will assist you with the same.</u></em><strong>&nbsp;</strong>Return after 3 hrs. in the same sharing boat to the jetty. Our tour manager will meet and assist with car transfers. Enroute proceed to&nbsp;<strong>Something Different – A Beach Side Café (Highest Reviewed Restaurant on Tripadvisor.com)</strong>&nbsp;and enjoy a&nbsp;<strong>complimentary</strong>&nbsp;pint of&nbsp;<strong>Domestic Beer/Glass of mocktail/ Glass of Soft drink&nbsp;</strong>per person from Set Menu (Any one). Later proceed to the hotel. Evening at leisure.</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<em>The offer is exclusive to our guests only and can be availed by sharing the&nbsp;</em><strong><em><u>voucher number</u></em></strong><em>&nbsp;at Something Different – A Beach Side Café, only during lunch hours. The guest will be taken to the café enroute from Elephant Beach to their hotel. This offer can be availed per guest on double occupancy, extra adult/ child (above 5 yrs. only) with or without mattress. Child of 5 yrs and below (Infant) will not be entitled to this offer. Any extra drinks or food items will be on chargeable basis.</em></p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<strong><em><u>T&amp;C:</u></em></strong><em>&nbsp;If the guest does not avail the drink there will be no refund as the same is provided complimentary to all guests. Drinks are non-transferrable and cannot be shifted to dinner. The offer must be availed on the day of Elephant Beach excursion only.</em></p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<strong><em><u>The beverages can be consumed only in the restaurant premises as per the excise rules.</u></em></strong></p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Alcohol is strictly prohibited on Elephant Beach.</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;The boats to Elephant Beach are managed by a boat association who need individual guest consent forms after which boats are allotted based on rotation and sharing basis. Due to limited boats, guest may have to wait until their boat is allotted and please note that we have no control over the wait time.&nbsp;</p><p>  </p><p><strong style=\"color: black;\">Day 5</strong></p><p><strong style=\"color: black;\">Havelock (Swaraj Dweep) - Neil Island (Shaheed Dweep)- O/N at Neil Island (Shaheed Dweep) - 03 Beach Visit</strong></p><p>  &nbsp;</p><p>Check-out from the Havelock hotel and head to the Havelock jetty to board the&nbsp;<strong>morning private ferry from Havelock (Swaraj Dweep) to Neil (Shaheed Dweep)</strong>&nbsp;(Journey time is 1.5 / 2.5 hrs). On arrival at Neil (Shaheed Dweep), our team will meet the guest at the exit gate and then the guest will be head to visit&nbsp;<strong><u>Bharatpur,</u>&nbsp;<u>Laxmanpur beach</u>&nbsp;and&nbsp;<u>Natural Bridge</u>&nbsp;</strong>(also known as Howrah Bridge by the locals - this can be accessed only during the Low Tide)<strong>&nbsp;</strong>and transfer to their Neil hotel. Enjoy a comfortable overnight stay and evening at leisure.</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Do note that all Havelock hotels have an early morning check-out time and late check-out is provided at the discretion of the hotel management and subject to availability.</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Guest should be ready for check-in at the Havelock private ferry counter at least an hour prior to the vessel departure time.</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;The three-beach visit is subject to tide timings and our representative will update the exact timing based on the tide.<em>&nbsp;</em></p><p><br></p><p><strong style=\"color: black;\">Day 6</strong></p><p><strong style=\"color: black;\">Neil Island (Shaheed Dweep) - Port Blair</strong></p><p><br></p><p> Wake up to the quaint and mesmerizing Neil Island (Shaheed Dweep) also called the \'Vegetable bowl of Andamans\' and check-out as per hotel allocated time and then, proceed to the Neil (Shaheed Dweep) jetty to board the&nbsp;<strong>afternoon private ferry (NL-PB) Neil Island (Shaheed Dweep) - Port Blair.</strong>&nbsp;On arrival at Port Blair, our team will meet the guest at the exit gate of the jetty and will be dropped to their Port Blair hotel. Evening at leisure.&nbsp;</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Do note that all Neil (Shaheed Dweep) hotels have an early morning check-out time and late check-out is provided at the discretion of the hotel management and subject to availability.</p><p><strong><u>OPTIONAL TOURS AT PORT BLAIR&nbsp;(SUBJECT TO MORNING FERRY AVAILABILITY FROM NEIL TO PORT BLAIR)</u></strong></p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Visit to Chidiyatapu (Sunset Point): INR 2500 + 5% GST Per Car.</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Visit to Wandoor Beach: INR 2500 + 5% GST Per Car.</p><p>Visit to Ross Island: INR 1000 + 5% GST Per Car &amp; INR 600 + 5% GST Per Person for Boat Charge.&nbsp;</p><p><br></p><p><strong style=\"color: black;\">Day 7</strong></p><p><strong style=\"color: black;\">Port Blair Airport</strong></p><p><br></p><p>  Enjoy your breakfast and check-out from the Port Blair hotel as per the hotel allocated time. Head&nbsp;<strong>straight to the airport</strong>&nbsp;to board the departure flight. Have a safe trip home taking back fond memories of these stunning islands.</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Do note that all Port Blair hotels have an early morning check-out time and late check-out is provided at the discretion of the hotel management and subject to availability.</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Port Blair airport has a small single runway and usually with a heavy rush of tourists. Request all guests to report at least 1.5hrs before departure flight timing. </p>', '<p><br></p>', '{}', 'Continental Plan (CP)', '2025-11-01 07:37:47', '2025-11-01 07:37:47', '8b1d1948-ec46-47ad-b2a9-25692600377e', '0d88fbdc-1552-4281-a5de-206a35a3f42d', '30102025027_Q02', NULL, '{\"1761817219408\":{\"adults\":\"69469\",\"extraAdults\":\"\",\"childWithBed\":\"\",\"childWithoutBed\":\"\",\"childsBelow5\":\"\",\"remarks\":\"\",\"rows\":[{\"key\":\"1761817253841\",\"hotelName\":\"  Hotel Symphony Samudra\",\"destination\":\"Port Blair\",\"checkIn\":\"2025-11-23\",\"checkOut\":\"2025-11-25\",\"roomCategory\":\"AC Casa Tropicana (Hotel with Infinity Pool)\",\"noOfRooms\":\"1\"},{\"key\":\"1761817341440\",\"hotelName\":\" Hotel CGH Earth\",\"destination\":\"Havelock\",\"checkIn\":\"2025-11-25\",\"checkOut\":\"2025-11-27\",\"roomCategory\":\"Tilar Siro - Sea Facing Room\",\"noOfRooms\":\"1\"},{\"key\":\"1761817414211\",\"hotelName\":\"   Hotel Sea Shell Samssara\",\"destination\":\"Neil Island\",\"checkIn\":\"2025-11-27\",\"checkOut\":\"2025-11-28\",\"roomCategory\":\"AC Lagoona Pool View\",\"noOfRooms\":\"1\"},{\"key\":\"1761817448794\",\"hotelName\":\"  Hotel Symphony Samudra\",\"destination\":\"Port Blair\",\"checkIn\":\"2025-11-28\",\"checkOut\":\"2025-11-29\",\"roomCategory\":\"AC Casa Tropicana (Hotel with Infinity Pool)\",\"noOfRooms\":\"1\"}]},\"1761817251060\":{\"adults\":\"83503\",\"extraAdults\":\"\",\"childWithBed\":\"\",\"childWithoutBed\":\"\",\"childsBelow5\":\"\",\"remarks\":\"\",\"rows\":[{\"key\":\"1761817484856\",\"hotelName\":\"Hotel Symphony Samudra\",\"destination\":\"Port Blair\",\"checkIn\":\"2025-11-23\",\"checkOut\":\"2025-11-25\",\"roomCategory\":\"AC Casa Tropicana (Hotel with Infinity Pool)\",\"noOfRooms\":\"1\"},{\"key\":\"1761817485673\",\"hotelName\":\"Taj Exotica and Spa\",\"destination\":\"Havelock\",\"checkIn\":\"2025-11-25\",\"checkOut\":\"2025-11-27\",\"roomCategory\":\"AC Deluxe villa\",\"noOfRooms\":\"1\"},{\"key\":\"1761817486214\",\"hotelName\":\"Hotel Sea Shell Samssara\",\"destination\":\"Neil Island\",\"checkIn\":\"2025-11-27\",\"checkOut\":\"2025-11-28\",\"roomCategory\":\"AC Lagoona Pool View\",\"noOfRooms\":\"1\"},{\"key\":\"1761817486745\",\"hotelName\":\"Hotel Symphony Samudra\",\"destination\":\"Port Blair\",\"checkIn\":\"2025-11-28\",\"checkOut\":\"2025-11-29\",\"roomCategory\":\"AC Casa Tropicana (Hotel with Infinity Pool)\",\"noOfRooms\":\"1\"}]}}'),
('d80ccb0c-8d8f-41ed-952e-98eba3884c34', '27022026038', 'draft', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 10:27:04', '2026-02-27 10:27:04', NULL, '74e78145-addf-4775-9806-7d9116108aa5', '27022026038_Q01', NULL, NULL);
