('eb4f9d3b-3b50-4c42-abca-ba13dc114a1f', '17112025030', 'draft', '<ul><li>Airport transfers on PVT basis</li><li>Intercity transfers on PVT basis</li><li>Hotel accommodation on double/extra bed basis</li><li>Meal plan as per hotel</li></ul>', '<ul><li>Main &amp; internal flights</li><li>Visa &amp; OTB charges</li><li>Anything not mentioned in inclusions</li><li>Any optional sightseeing</li><li>Insurance</li></ul>', '<p><strong>2nd Day (Fri, 16 Jan)</strong></p><ul><li>DXB Airport to Deira/ Bur Dubai Hotel - Arrival - PVT (1-Vehicle 14 Seater)</li><li>Yacht - PVT - Two Way (1-Vehicle 14 Seater)</li><li>45 Feet Yacht per hour Rate/ Can Fit upto (12-14 PAX) - Ticket (1 Unit)</li></ul><p><br></p><p><strong>3rd Day (Sat, 17 Jan)</strong></p><ul><li>Half Day Dubai City Tour - PVT (1-Vehicle 14 Seater)</li><li>burj khalifa 124th + 125th Non-Prime Hours Tickets (7 AM- 2:30 PM) (7:30 PM - 11 PM) - Ticket (7 Adults)</li><li>Palm Monorail 01 Way - Ticket (7 Adults)</li><li>01 Way Transfer Deira/Bur Dubai to Deira/Bur Dubai - PVT - One Way (1-Vehicle 14 Seater)</li></ul><p><br></p><p><strong>4th Day (Sun, 18 Jan)</strong></p><ul><li>Miracle Garden + Global - PVT - Three Way (1-Vehicle 14 Seater)</li><li>Miracle Garden Ticket - Ticket (7 Adults)</li><li>Global Village Ticket - Ticket (7 Adults)</li></ul><p><br></p><p><strong>5th Day (Mon, 19 Jan)</strong></p><ul><li>Dubai Frame From Deira/ Bur Dubai - PVT - Two Way (1-Vehicle 14 Seater)</li><li>Dubai Frame Ticket - Ticket (7 Adults)</li><li>Desert Safari Pvt - Ticket&nbsp;<strong>(2 Unit)</strong></li><li><strong>Premium Royal Vision Camp - Ticket (7 Adults)</strong></li></ul><p><br></p><p><strong>6th Day (Tue, 20 Jan)</strong></p><ul><li>Future Museum From SZR/Barsha/Marina - PVT - Two Way (1-Vehicle 14 Seater)</li><li>Museum of The Future&nbsp;<strong>(Tickets are subject to availability)</strong>&nbsp;- Ticket (7 Adults)</li><li>Jebel Jais Zipline - Ras Al khaimah - Ticket (7 Adults)</li><li>View At Palm - PVT - Two Way (1-Vehicle 14 Seater)</li><li>View at the Palm Jumeirah Dubai Non-Prime Time (9 AM - 4:30 PM) (7:30 PM) - Ticket (7 Adults)</li></ul><p><br></p><p><strong>7th Day (Wed, 21 Jan)</strong></p><ul><li>Inter Hotel Deira/Bur Dubai to Al Barsha/ Marina - PVT - One Way (1-Vehicle 14 Seater)</li></ul><p><br></p><p><strong>8th Day (Thu, 22 Jan) [10 Hrs]</strong></p><ul><li>Abu Dhabi - Full Day - City Tour + BAPS Temple&nbsp;<strong>[Closed on Monday]&nbsp;</strong>PVT (1-Vehicle 14 Seater)</li></ul><p><br></p><p><strong>9th Day (Fri, 23 Jan)</strong></p><ul><li>Free Park access at Yas island - Park With Stay at Yas island (7 Adults)</li></ul><p><br></p><p><strong>10th Day (Sat, 24 Jan)</strong></p><ul><li>Free Park access at Yas island - Park With Stay at Yas island (7 Adults)</li><li>Abu Dhabi Hotel to Abu Dhabi Airport - Departure - PVT (1-Vehicle 14 Seater)</li></ul>', '<ul><li>UAE tourist visa charges INR 7800/- PP</li><li>OTB charges</li></ul>', '{\"1763382111860\":{\"ratePerPerson\":\"34820\",\"remarks\":\"Rate are subject to change at the actual time of booking\",\"rows\":[{\"key\":\"1763622628788\",\"travelDate\":\"2026-01-16\",\"flightNo\":\"6E 1477\",\"departure\":\"AMD\",\"arrival\":\"DXB\",\"departureTime\":\"02:25\",\"arrivalTime\":\"04:05\",\"passenger\":\"1\",\"baggage\":\"30\"},{\"key\":\"1763622629614\",\"travelDate\":\"2026-01-25\",\"flightNo\":\"6E 1432 .\",\"departure\":\"AUH\",\"arrival\":\"AMD\",\"departureTime\":\"01:25\",\"arrivalTime\":\"05:35\",\"passenger\":\"1\",\"baggage\":\"30\"}]}}', 'Continental Plan (CP)', '2026-03-13 12:02:21', '2026-03-13 12:04:12', '30f422d1-322a-490d-9a50-f49cdeb7fe55', '0d88fbdc-1552-4281-a5de-206a35a3f42d', '17112025030_Q02', NULL, '{\"1763375295619\":{\"adults\":\"1490\",\"extraAdults\":\"1490\",\"childWithBed\":\"\",\"childWithoutBed\":\"\",\"childsBelow5\":\"\",\"remarks\":\"Above given package rate are in USD \\nRate are subject to change at the actual time of booking\",\"rows\":[{\"key\":\"1763622650779\",\"hotelName\":\