--
-- Table structure for table `visas`
--

DROP TABLE IF EXISTS `visas`;
CREATE TABLE `visas` (
  `id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `fullName` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
